(function () {
    cc.SicBoGroupUserView = cc.Class({
        "extends": cc.Component,
        properties: {
			loading: cc.Node,
			nodePanel: cc.Node,
			btnHidePanel: cc.Node,
			groupUserListView: cc.SicboUserListView
		},
		
        getGroupUser: function () {
			this.loading.active = true;
            var getGroupUserCommand = new cc.SicBoGroupUserCommand;
            getGroupUserCommand.execute(this);
        },

        onGetGroupUserResponse: function (response) {
			this.loading.active = false;
            var list = response;
            if (list !== null && list.length > 0) {
                this.groupUserListView.resetList();
                this.groupUserListView.initialize(list);
            }
        },

        onClickShowGroupUser: function () {
			this.getGroupUser();
			this.btnHidePanel.active = true;
            cc.tween(this.nodePanel)
                .to(0.3, { position: cc.v2(670, this.nodePanel.y) })
                .start();
        },

        onClickHideGroupUser: function () {
			this.groupUserListView.resetList();
            cc.tween(this.nodePanel)
                .to(0.3, { position: cc.v2(940, this.nodePanel.y) })
                .start();
			this.btnHidePanel.active = false;
        },
    })
}).call(this)